CREATE TABLE public.workflow_tickets (risk_level text, risk_score integer, last_reviewed_at timestamp without time zone, ticket_number character varying NOT NULL, entity_id integer NOT NULL, metadata jsonb DEFAULT '{}'::jsonb, assigned_at timestamp without time zone, review_count integer NOT NULL DEFAULT 0, current_stage_id integer, status text NOT NULL DEFAULT 'submitted'::text, started_at timestamp without time zone, workflow_definition_id integer NOT NULL, submitted_at timestamp without time zone NOT NULL DEFAULT now(), priority text NOT NULL DEFAULT 'normal'::text, id integer NOT NULL DEFAULT nextval('workflow_tickets_id_seq'::regclass), sub_status text, last_reviewed_by character varying, completed_at timestamp without time zone, created_at timestamp without time zone NOT NULL DEFAULT now(), entity_type text NOT NULL, updated_at timestamp without time zone NOT NULL DEFAULT now(), assigned_to_id character varying, due_at timestamp without time zone);
CREATE TABLE public.workflow_transitions (ticket_id integer NOT NULL, notes text, from_stage_id integer, id integer NOT NULL DEFAULT nextval('workflow_transitions_id_seq'::regclass), reason text, triggered_by character varying, transition_type text NOT NULL, triggered_by_system boolean NOT NULL DEFAULT false, to_value text, from_value text, created_at timestamp without time zone NOT NULL DEFAULT now(), to_stage_id integer);